# Explorer empty-starter synthesis from E1 + instruction tokens
def assess(record: dict) -> str:
    required = {"case_id", "query", "docs", "metric", "version", "expected_top"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    ok = max(record["docs"], key=lambda k: sum(a*b for a,b in zip(record["query"],record["docs"][k]))) == record["expected_top"]
    return "PASS" if ok else "REJECT_EMBEDDING_RANK"

